import { createRouter, createWebHashHistory } from "vue-router";
const routes = [
	{
		path: "/",
		//redirect 是重新定向
		redirect: "/login",
	},
	{
		path: "/login",
		name: "login",
		component: () => import("../views/Login/index.vue"),
	},
	{
		path: "/home",
		name: "home",
		component: () => import("../views/Home/index.vue"),
	},
	{
		path: "/checkout",
		name: "checkout",
		component: () => import("../views/Checkout/index.vue"),
	},
	{
		path: "/deskbinding",
		name: "deskbinding",
		component: () => import("../views/DeskBinding/index.vue"),
	},
	{
		path: "/jobinfo",
		name: "jobinfo",
		component: () => import("../views/Jobinfo/index.vue"),
	},
	{
		path: "/numupdate",
		name: "numupdate",
		component: () => import("../views/Numupdate/index.vue"),
	},
	{
		path: "/linebit",
		name: "linebit",
		component: () => import("../views/Linebit/index.vue"),
	},
];

const router = createRouter({
	history: createWebHashHistory(),
	routes,
});

// 路由守卫
router.beforeEach((to, from, next) => {
	const token = localStorage.getItem("pad_token");
	if (!token) {
		// 如果没有token,不去login不行
		if (to.name !== "login") {
			next({
				name: "login",
			});
		} else {
			next();
		}
	} else {
		// 有token
		if (to.name == "login") {
			// 如果有token还要去login,跳转到home
			next({ path: "/home" });
		} else {
			next();
		}
	}
});
export default router;
